import{_ as e}from"./chunks/demo-doc.D32o-ZLW.js";import{c as o,Q as c,j as t,m as a}from"./chunks/framework.BkjtU8k0.js";const x=JSON.parse('{"title":"支持格式","description":"","frontmatter":{},"headers":[],"relativePath":"guide/formats.md","filePath":"guide/formats.md","lastUpdated":1779097958000}'),l={name:"guide/formats.md"};function i(r,d,s,h,n,p){return c(),t("div",null,[...d[0]||(d[0]=[a('<h1 id="支持格式" tabindex="-1">支持格式 <a class="header-anchor" href="#支持格式" aria-label="Permalink to &quot;支持格式&quot;">​</a></h1><div class="doc-kicker">Runtime Truth</div><p class="doc-lead"> 当前版本内置 <strong>59 个扩展名映射</strong>，覆盖 <strong>11 条预览链路</strong>。 这一页不是“计划支持什么”，而是以当前代码里已经注册好的渲染器为准，告诉你项目现在到底能处理哪些格式、分别走哪条渲染链路，以及在真实业务里应该怎么选。 </p><div class="doc-grid"><div class="doc-card"><h3>59 个扩展名映射</h3><p>覆盖 Office、PDF、OFD、CAD、Markdown、图片、代码/文本和视频等常见附件类型。</p></div><div class="doc-card"><h3>按需异步加载</h3><p>OFD、CAD、PDF、Office、Markdown、代码高亮等渲染器都会拆成独立异步块，命中格式时才加载。</p></div><div class="doc-card"><h3>两条输入路径</h3><p>既可以用 <code>url</code> 直接预览，也可以在业务侧拿到文件后二次包装成 <code>File</code> 再传入。</p></div><div class="doc-card"><h3>以体验边界为准</h3><p>不同格式会走不同解析链路，兼容优先的格式与高保真格式在样式还原上并不完全一样。</p></div></div><h2 id="当前支持矩阵" tabindex="-1">当前支持矩阵 <a class="header-anchor" href="#当前支持矩阵" aria-label="Permalink to &quot;当前支持矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>分类</th><th>扩展名</th><th>渲染链路</th><th>当前表现</th><th>更适合的场景</th></tr></thead><tbody><tr><td>Word</td><td><code>docx</code></td><td><code>docx-preview</code></td><td>版式、段落和文档结构还原更完整</td><td>新生成的 Word 文档、正式公文、模板文档</td></tr><tr><td>Word</td><td><code>doc</code></td><td><code>msdoc-viewer</code></td><td>使用 Word 风格页面容器，页面居中显示在灰色工作台中</td><td>存量老文档、历史附件回溯</td></tr><tr><td>Excel</td><td><code>xlsx</code></td><td><code>styled-exceljs</code> + <code>e-virt-table</code></td><td>支持虚拟滚动、列宽/行高、合并单元格和常见样式</td><td>大表格预览、报表、需要保留结构和样式的业务</td></tr><tr><td>Excel 兼容格式</td><td><code>xlsm</code>、<code>xlsb</code>、<code>xls</code>、<code>csv</code>、<code>ods</code>、<code>fods</code>、<code>numbers</code></td><td><code>styled-exceljs</code> + <code>e-virt-table</code></td><td>统一读取数据、尺寸和可用样式，按浏览器能力渐进还原</td><td>老表格、跨平台导出的表格、轻量数据查看</td></tr><tr><td>PowerPoint</td><td><code>pptx</code></td><td>自定义 PPTX 渲染器</td><td>以页面展示为主，适合浏览幻灯片内容</td><td>汇报材料、说明文档、培训课件</td></tr><tr><td>PDF</td><td><code>pdf</code></td><td><code>pdfjs-dist</code></td><td>浏览器端 PDF 渲染，支持缩放工具栏、页码状态和可显隐导航窗格</td><td>合同、票据、版式稳定文件</td></tr><tr><td>OFD</td><td><code>ofd</code></td><td><code>DLTech21/ofd.js</code> 源码</td><td>使用浏览器端 OFD 解析和页面渲染，避开 npm dist 授权 wasm 分支</td><td>电子发票、公文、国产版式归档材料</td></tr><tr><td>CAD</td><td><code>dxf</code></td><td><code>@cadview/core</code></td><td>Canvas 方式浏览 DXF 图纸，支持缩放、平移、图层显示控制</td><td>工程图纸、二维 CAD 附件</td></tr><tr><td>CAD 兼容入口</td><td><code>dwg</code></td><td>CAD 兼容提示</td><td>DWG 属于专有二进制格式，当前不内置 GPL 解析器，会提示转换为 DXF 后预览</td><td>需要兼容上传入口但不希望引入 GPL 运行时代码的业务</td></tr><tr><td>Markdown</td><td><code>md</code>、<code>markdown</code></td><td>Markdown 渲染器</td><td>保留 Markdown 阅读样式</td><td>README、知识文档、开发说明</td></tr><tr><td>图片</td><td><code>gif</code>、<code>jpg</code>、<code>jpeg</code>、<code>bmp</code>、<code>tiff</code>、<code>tif</code>、<code>png</code>、<code>svg</code>、<code>webp</code></td><td>图片渲染器</td><td>原生图片浏览</td><td>图片附件、设计稿、截图、Logo</td></tr><tr><td>代码/文本</td><td><code>txt</code>、<code>json</code>、<code>js</code>、<code>mjs</code>、<code>cjs</code>、<code>css</code>、<code>java</code>、<code>py</code>、<code>html</code>、<code>htm</code>、<code>jsx</code>、<code>ts</code>、<code>tsx</code>、<code>xml</code>、<code>log</code>、<code>vue</code>、<code>yaml</code>、<code>yml</code>、<code>ini</code>、<code>sh</code>、<code>bash</code>、<code>sql</code>、<code>go</code>、<code>rs</code>、<code>php</code>、<code>c</code>、<code>cpp</code>、<code>cc</code>、<code>h</code>、<code>hpp</code>、<code>cs</code>、<code>diff</code></td><td><code>highlight.js</code></td><td>按源码方式展示并轻量高亮，不执行脚本</td><td>配置文件、日志、代码片段、接口响应</td></tr><tr><td>视频</td><td><code>mp4</code></td><td>浏览器原生视频播放器</td><td>原生播放、带控制条</td><td>演示视频、录屏材料</td></tr></tbody></table><h2 id="按类型看体验和边界" tabindex="-1">按类型看体验和边界 <a class="header-anchor" href="#按类型看体验和边界" aria-label="Permalink to &quot;按类型看体验和边界&quot;">​</a></h2><h3 id="word-文档" tabindex="-1">Word 文档 <a class="header-anchor" href="#word-文档" aria-label="Permalink to &quot;Word 文档&quot;">​</a></h3><ul><li><code>docx</code> 使用 <code>docx-preview</code>，适合正文、表格、图片和常规版式较多的现代 Word 文档。</li><li><code>doc</code> 使用 <code>msdoc-viewer</code>，并额外套用 Word 风格页面容器。它不只是“把内容吐出来”，而是尽量保留文档阅读时的页面感。</li><li>如果你的业务能控制导出格式，优先推荐 <code>docx</code>；如果你面对的是存量老文档，当前 <code>.doc</code> 已经可以作为正式能力对外说明。</li></ul><div class="doc-shot"><img src="'+e+'" alt="DOC 文档按 Word 风格展示"><p class="doc-caption">`.doc` 文件现在会显示在灰色工作台中的白色纸张上，页面居中，阅读路径更接近真实 Word 阅读体验。</p></div><h3 id="表格类文件" tabindex="-1">表格类文件 <a class="header-anchor" href="#表格类文件" aria-label="Permalink to &quot;表格类文件&quot;">​</a></h3><ul><li>表格类文件统一走 <code>styled-exceljs</code> 解析和 <code>e-virt-table</code> 虚拟渲染，适合需要保留表格结构、合并单元格和视觉层级的场景。</li><li><code>xlsm</code>、<code>xlsb</code>、<code>xls</code>、<code>csv</code>、<code>ods</code>、<code>fods</code>、<code>numbers</code> 会读取格式中能表达的数据、尺寸和样式；部分格式本身不包含完整样式时，会按可用信息渐进还原。</li><li>如果你正在设计业务导出格式，优先选 <code>xlsx</code>；如果你只是需要把历史附件打开看内容，兼容链路已经足够实用。</li></ul><h3 id="演示文稿、pdf-与-ofd" tabindex="-1">演示文稿、PDF 与 OFD <a class="header-anchor" href="#演示文稿、pdf-与-ofd" aria-label="Permalink to &quot;演示文稿、PDF 与 OFD&quot;">​</a></h3><ul><li><code>pptx</code> 适合浏览幻灯片内容、做方案回看和日常演示，不需要 Office 本体参与。</li><li><code>pdf</code> 走 <code>pdfjs-dist</code>，通常是版式最稳定的一类文件，适合合同、流程单、正式成品材料。当前 PDF 视图提供顶部缩放工具栏、页码状态和可显隐页面导航窗格。</li><li><code>ofd</code> 走 <code>DLTech21/ofd.js</code> 仓库源码，用于国产版式文档在线预览。npm dist 当前会在 wasm 解析层返回授权错误，组件改用同仓库的纯 JS 解析/渲染链路，OFD 依赖仍保持按需异步加载。</li><li>如果你更在意“展示结果必须完全稳定”，优先考虑 <code>pdf</code> / <code>ofd</code> 这类版式成品；如果你需要保留可编辑文件的阅读入口，优先用 <code>pptx</code>。</li></ul><h3 id="cad-图纸" tabindex="-1">CAD 图纸 <a class="header-anchor" href="#cad-图纸" aria-label="Permalink to &quot;CAD 图纸&quot;">​</a></h3><ul><li><code>dxf</code> 走 <code>@cadview/core</code>，提供 Canvas 图纸预览、缩放、平移和图层显隐能力。</li><li><code>dwg</code> 当前注册为兼容入口，但不会直接解析。DWG 格式通常需要专用转换或 GPL 授权运行时，组件会给出清晰提示，推荐业务侧转换为 <code>dxf</code> 后再预览。</li><li>如果你要在生产系统里稳定预览 CAD 文件，建议把 DXF 作为前端预览标准格式，并在上传或归档环节统一转换。</li></ul><h3 id="markdown、代码与文本" tabindex="-1">Markdown、代码与文本 <a class="header-anchor" href="#markdown、代码与文本" aria-label="Permalink to &quot;Markdown、代码与文本&quot;">​</a></h3><ul><li><code>md</code> 和 <code>markdown</code> 会按 Markdown 阅读样式展示，适合项目说明、知识文档和内部手册。</li><li>代码和文本文件会使用 <code>highlight.js</code> 做轻量高亮，按扩展名匹配语言，不命中时会自动退回纯文本。</li><li>这里有一个很重要的边界：<code>html</code> 文件会被当作源码看，而不是在预览器里当网页执行。这是更安全、也更可控的默认策略。</li></ul><h3 id="图片与视频" tabindex="-1">图片与视频 <a class="header-anchor" href="#图片与视频" aria-label="Permalink to &quot;图片与视频&quot;">​</a></h3><ul><li>图片类支持 <code>gif</code>、<code>jpg</code>、<code>jpeg</code>、<code>bmp</code>、<code>tiff</code>、<code>tif</code>、<code>png</code>、<code>svg</code>、<code>webp</code>。</li><li><code>svg</code> 会作为图片来展示，很适合拿来放矢量图标、流程图和品牌素材。</li><li>视频当前支持 <code>mp4</code>，使用浏览器原生播放器，适合最常见的演示和录屏场景。</li></ul><h2 id="真实业务里怎么选" tabindex="-1">真实业务里怎么选 <a class="header-anchor" href="#真实业务里怎么选" aria-label="Permalink to &quot;真实业务里怎么选&quot;">​</a></h2><ul><li>你能控制导出格式：优先使用 <code>docx</code>、<code>xlsx</code>、<code>pptx</code>、<code>pdf</code>、<code>ofd</code>、<code>dxf</code> 这类现代或稳定交换格式。</li><li>你要兼容历史附件：<code>.doc</code> 与 <code>xls/xlsm/xlsb/csv/ods</code> 这一组已经有正式链路，但要接受它们与现代格式在样式上的差异。</li><li>你要看日志、配置或代码：直接用代码/文本链路即可，重点是快速打开、检索内容和保持安全。</li><li>你在做品牌、示意图或视觉素材展示：<code>png</code>、<code>svg</code>、<code>webp</code> 这类图片格式会比转成文档更省心。</li><li>你要预览 CAD：优先沉淀 <code>dxf</code>，把 <code>dwg</code> 作为上传兼容和转换前提示。</li></ul><h2 id="不支持的格式会怎样" tabindex="-1">不支持的格式会怎样 <a class="header-anchor" href="#不支持的格式会怎样" aria-label="Permalink to &quot;不支持的格式会怎样&quot;">​</a></h2><p>如果文件扩展名没有命中已注册渲染器，组件会显示“不支持当前格式在线预览”的提示，引导用户下载后查看或转换格式。</p><div class="doc-note"> 最稳妥的做法，不是只看这张表，而是把你业务里最关键的那几类真实文件各准备一份样本，走一遍本地 Demo 和接入页联调。这样你拿去对外说明时，底气会更足。 </div>',25)])])}const u=o(l,[["render",i]]);export{x as __pageData,u as default};
